     1→/**
     2→ * MMS Toolbar
     3→ *
     4→ * View controls, navigation, and action buttons.
     5→ * Based on specs/006-user-interface.md Section 6.2.
     6→ */
     7→
     8→import {
     9→  Button,
    10→  ButtonGroup,
    11→  Divider,
    12→  Popover,
    13→  Menu,
    14→  MenuDivider,
    15→  MenuItem,
    16→  Tag,
    17→} from '@blueprintjs/core';
    18→import { format } from 'date-fns';
    19→
    20→import { useCanvas, useScenario, useUi } from '../../store';
    21→import type { CanvasSliceState } from '../../store/slices/canvas';
    22→import type { ScenarioSliceState } from '../../store/slices/scenario';
    23→import type { UiSliceState } from '../../store/slices/ui';
    24→
    25→export function Toolbar() {
    26→  const { state: canvasStateRaw, actions: canvasActions } = useCanvas();
    27→  const { state: scenarioStateRaw } = useScenario();
    28→  const { state: uiStateRaw, actions: uiActions } = useUi();
    29→
    30→  const canvasState = canvasStateRaw as unknown as CanvasSliceState;
    31→  const scenarioState = scenarioStateRaw as unknown as ScenarioSliceState;
    32→  const uiState = uiStateRaw as unknown as UiSliceState;
    33→
    34→  const handleZoomLevelClick = (level: 'STRATEGIC' | 'TACTICAL' | 'OPERATIONAL') => {
    35→    const targetZoom =
    36→      level === 'STRATEGIC' ? 2 :
    37→      level === 'TACTICAL' ? 10 :
    38→      level === 'OPERATIONAL' ? 14 : 10;
    39→
    40→    canvasActions.setZoom(targetZoom);
    41→  };
    42→
    43→  const handleZoomIn = () => {
    44→    canvasActions.setZoom(Math.min(20, canvasState.zoom + 1));
    45→  };
    46→
    47→  const handleZoomOut = () => {
    48→    canvasActions.setZoom(Math.max(0, canvasState.zoom - 1));
    49→  };
    50→
    51→  const handleToday = () => {
    52→    canvasActions.goToToday();
    53→  };
    54→
    55→  const handlePrevPeriod = () => {
    56→    const start = new Date(canvasState.viewport.startDate);
    57→    const periodDays = canvasState.zoomLevel === 'STRATEGIC' ? 365 :
    58→                       canvasState.zoomLevel === 'TACTICAL_WIDE' ? 90 :
    59→                       canvasState.zoomLevel === 'TACTICAL' ? 28 : 7;
    60→    start.setDate(start.getDate() - periodDays);
    61→    canvasActions.setViewport({
    62→      startDate: start.toISOString().split('T')[0],
    63→    });
    64→  };
    65→
    66→  const handleNextPeriod = () => {
    67→    const start = new Date(canvasState.viewport.startDate);
    68→    const periodDays = canvasState.zoomLevel === 'STRATEGIC' ? 365 :
    69→                       canvasState.zoomLevel === 'TACTICAL_WIDE' ? 90 :
    70→                       canvasState.zoomLevel === 'TACTICAL' ? 28 : 7;
    71→    start.setDate(start.getDate() + periodDays);
    72→    canvasActions.setViewport({
    73→      startDate: start.toISOString().split('T')[0],
    74→    });
    75→  };
    76→
    77→  const handleToggleLayer = (layer: 'complianceWindows' | 'manhourOverlay' | 'driftOverlay' | 'baselineShadow') => {
    78→    canvasActions.toggleLayer(layer);
    79→  };
    80→
    81→  const handlePublishBaseline = () => {
    82→    uiActions.openModal({ type: 'PUBLISH_BASELINE' });
    83→  };
    84→
    85→  const handleCreateScenario = () => {
    86→    uiActions.openModal({ type: 'CREATE_SCENARIO' });
    87→  };
    88→
    89→  const handleRunOptimizer = () => {
    90→    uiActions.openModal({ type: 'RUN_OPTIMIZER' });
    91→  };
    92→
    93→  const handleImportData = () => {
    94→    uiActions.openModal({ type: 'IMPORT_DATA' });
    95→  };
    96→
    97→  const handleToggleMinimap = () => {
    98→    canvasActions.toggleMinimap();
    99→  };
   100→
   101→  const handleToggleGrid = () => {
   102→    canvasActions.toggleGrid();
   103→  };
   104→
   105→  const overlayMenu = (
   106→    <Menu>
   107→      <MenuItem
   108→        icon={canvasState.layers.complianceWindows ? 'tick' : 'blank'}
   109→        text="Compliance Windows"
   110→        onClick={() => handleToggleLayer('complianceWindows')}
   111→      />
   112→      <MenuItem
   113→        icon={canvasState.layers.manhourOverlay ? 'tick' : 'blank'}
   114→        text="Man-hour Utilization"
   115→        onClick={() => handleToggleLayer('manhourOverlay')}
   116→      />
   117→      <MenuItem
   118→        icon={canvasState.layers.driftOverlay ? 'tick' : 'blank'}
   119→        text="Drift Analysis"
   120→        onClick={() => handleToggleLayer('driftOverlay')}
   121→      />
   122→      <MenuItem
   123→        icon={canvasState.layers.baselineShadow ? 'tick' : 'blank'}
   124→        text="Baseline Shadow"
   125→        onClick={() => handleToggleLayer('baselineShadow')}
   126→      />
   127→      <MenuDivider />
   128→      <MenuItem
   129→        icon={canvasState.showMinimap ? 'tick' : 'blank'}
   130→        text="Minimap"
   131→        onClick={handleToggleMinimap}
   132→      />
   133→      <MenuItem
   134→        icon={canvasState.showGrid ? 'tick' : 'blank'}
   135→        text="Grid"
   136→        onClick={handleToggleGrid}
   137→      />
   138→    </Menu>
   139→  );
   140→
   141→  const exportMenu = (
   142→    <Menu>
   143→      <MenuItem icon="document" text="Export PM Schedule (Excel)" />
   144→      <MenuItem icon="document" text="Generate Report (PDF)" />
   145→    </Menu>
   146→  );
   147→
   148→  const isStrategic = canvasState.zoomLevel === 'STRATEGIC' || canvasState.zoomLevel === 'TACTICAL_WIDE';
   149→  const isTactical = canvasState.zoomLevel === 'TACTICAL';
   150→  const isOperational = canvasState.zoomLevel === 'OPERATIONAL' || canvasState.zoomLevel === 'DETAIL';
   151→
   152→  return (
   153→    <div className="mms-toolbar" data-testid="toolbar" style={{
   154→      display: 'flex',
   155→      justifyContent: 'space-between',
   156→      padding: '8px 16px',
   157→      borderBottom: '1px solid var(--pt-divider-black, #e1e8ed)',
   158→      backgroundColor: 'var(--pt-app-background-color, #f5f8fa)',
   159→    }}>
   160→      <div style={{ display: 'flex', gap: '16px', alignItems: 'center' }}>
   161→        {/* Zoom Level Buttons */}
   162→        <ButtonGroup>
   163→          <Button
   164→            text="Strategic"
   165→            active={isStrategic}
   166→            onClick={() => handleZoomLevelClick('STRATEGIC')}
   167→          />
   168→          <Button
   169→            text="Tactical"
   170→            active={isTactical}
   171→            onClick={() => handleZoomLevelClick('TACTICAL')}
   172→          />
   173→          <Button
   174→            text="Operational"
   175→            active={isOperational}
   176→            onClick={() => handleZoomLevelClick('OPERATIONAL')}
   177→          />
   178→        </ButtonGroup>
   179→
   180→        <Divider />
   181→
   182→        {/* Navigation */}
   183→        <ButtonGroup>
   184→          <Button icon="chevron-left" onClick={handlePrevPeriod} />
   185→          <Button text="Today" onClick={handleToday} />
   186→          <Button icon="chevron-right" onClick={handleNextPeriod} />
   187→        </ButtonGroup>
   188→
   189→        <Tag minimal style={{ fontFamily: 'monospace' }}>
   190→          {format(new Date(canvasState.viewport.startDate), 'MMM yyyy')}
   191→        </Tag>
   192→
   193→        <Divider />
   194→
   195→        {/* Zoom Controls */}
   196→        <ButtonGroup>
   197→          <Button icon="zoom-out" onClick={handleZoomOut} disabled={canvasState.zoom <= 0} />
