   204→      </div>
   205→
   206→      <div style={{ display: 'flex', gap: '8px', alignItems: 'center' }}>
   207→        {/* Scenario Indicator */}
   208→        {scenarioState.activeScenarioId && (
   209→          <Tag intent="warning" icon="annotation">
   210→            Scenario Active
