/**
 * MMS Toolbar
 *
 * View controls, navigation, and action buttons.
 * Based on specs/006-user-interface.md Section 6.2.
 */

import {
  Button,
  ButtonGroup,
  Divider,
  Popover,
  Menu,
  MenuDivider,
  MenuItem,
  Tag,
} from '@blueprintjs/core';
import { format } from 'date-fns';

import { useCanvas, useScenario, useUi } from '../../store';
import type { CanvasSliceState } from '../../store/slices/canvas';
import type { ScenarioSliceState } from '../../store/slices/scenario';
import type { UiSliceState } from '../../store/slices/ui';

export function Toolbar() {
  const { state: canvasStateRaw, actions: canvasActions } = useCanvas();
  const { state: scenarioStateRaw } = useScenario();
  const { state: uiStateRaw, actions: uiActions } = useUi();

  const canvasState = canvasStateRaw as unknown as CanvasSliceState;
  const scenarioState = scenarioStateRaw as unknown as ScenarioSliceState;
  const uiState = uiStateRaw as unknown as UiSliceState;

  const handleZoomLevelClick = (level: 'STRATEGIC' | 'TACTICAL' | 'OPERATIONAL') => {
    const targetZoom =
      level === 'STRATEGIC' ? 2 :
      level === 'TACTICAL' ? 10 :
      level === 'OPERATIONAL' ? 14 : 10;

    canvasActions.setZoom(targetZoom);
  };

  const handleZoomIn = () => {
    canvasActions.setZoom(Math.min(20, canvasState.zoom + 1));
  };

  const handleZoomOut = () => {
    canvasActions.setZoom(Math.max(0, canvasState.zoom - 1));
  };

  const handleToday = () => {
    canvasActions.goToToday();
  };

  const handlePrevPeriod = () => {
    const start = new Date(canvasState.viewport.startDate);
    const periodDays = canvasState.zoomLevel === 'STRATEGIC' ? 365 :
                       canvasState.zoomLevel === 'TACTICAL_WIDE' ? 90 :
                       canvasState.zoomLevel === 'TACTICAL' ? 28 : 7;
    start.setDate(start.getDate() - periodDays);
    canvasActions.setViewport({
      startDate: start.toISOString().split('T')[0],
    });
  };

  const handleNextPeriod = () => {
    const start = new Date(canvasState.viewport.startDate);
    const periodDays = canvasState.zoomLevel === 'STRATEGIC' ? 365 :
                       canvasState.zoomLevel === 'TACTICAL_WIDE' ? 90 :
                       canvasState.zoomLevel === 'TACTICAL' ? 28 : 7;
    start.setDate(start.getDate() + periodDays);
    canvasActions.setViewport({
      startDate: start.toISOString().split('T')[0],
    });
  };

  const handleToggleLayer = (layer: 'complianceWindows' | 'manhourOverlay' | 'driftOverlay' | 'baselineShadow') => {
    canvasActions.toggleLayer(layer);
  };

  const handlePublishBaseline = () => {
    uiActions.openModal({ type: 'PUBLISH_BASELINE' });
  };

  const handleCreateScenario = () => {
    uiActions.openModal({ type: 'CREATE_SCENARIO' });
  };

  const handleRunOptimizer = () => {
    uiActions.openModal({ type: 'RUN_OPTIMIZER' });
  };

  const handleImportData = () => {
    uiActions.openModal({ type: 'IMPORT_DATA' });
  };

  const handleToggleMinimap = () => {
    canvasActions.toggleMinimap();
  };

  const handleToggleGrid = () => {
    canvasActions.toggleGrid();
  };

  const overlayMenu = (
    <Menu>
      <MenuItem
        icon={canvasState.layers.complianceWindows ? 'tick' : 'blank'}
        text="Compliance Windows"
        onClick={() => handleToggleLayer('complianceWindows')}
      />
      <MenuItem
        icon={canvasState.layers.manhourOverlay ? 'tick' : 'blank'}
        text="Man-hour Utilization"
        onClick={() => handleToggleLayer('manhourOverlay')}
      />
      <MenuItem
        icon={canvasState.layers.driftOverlay ? 'tick' : 'blank'}
        text="Drift Analysis"
        onClick={() => handleToggleLayer('driftOverlay')}
      />
      <MenuItem
        icon={canvasState.layers.baselineShadow ? 'tick' : 'blank'}
        text="Baseline Shadow"
        onClick={() => handleToggleLayer('baselineShadow')}
      />
      <MenuDivider />
      <MenuItem
        icon={canvasState.showMinimap ? 'tick' : 'blank'}
        text="Minimap"
        onClick={handleToggleMinimap}
      />
      <MenuItem
        icon={canvasState.showGrid ? 'tick' : 'blank'}
        text="Grid"
        onClick={handleToggleGrid}
      />
    </Menu>
  );

  const exportMenu = (
    <Menu>
      <MenuItem icon="document" text="Export PM Schedule (Excel)" />
      <MenuItem icon="document" text="Generate Report (PDF)" />
    </Menu>
  );

  const isStrategic = canvasState.zoomLevel === 'STRATEGIC' || canvasState.zoomLevel === 'TACTICAL_WIDE';
  const isTactical = canvasState.zoomLevel === 'TACTICAL';
  const isOperational = canvasState.zoomLevel === 'OPERATIONAL' || canvasState.zoomLevel === 'DETAIL';

  return (
    <div className="mms-toolbar" data-testid="toolbar" style={{
      display: 'flex',
      justifyContent: 'space-between',
      padding: '8px 16px',
      borderBottom: '1px solid var(--pt-divider-black, #e1e8ed)',
      backgroundColor: 'var(--pt-app-background-color, #f5f8fa)',
    }}>
      <div style={{ display: 'flex', gap: '16px', alignItems: 'center' }}>
        {/* Zoom Level Buttons */}
        <ButtonGroup>
          <Button
            text="Strategic"
            active={isStrategic}
            onClick={() => handleZoomLevelClick('STRATEGIC')}
          />
          <Button
            text="Tactical"
            active={isTactical}
            onClick={() => handleZoomLevelClick('TACTICAL')}
          />
          <Button
            text="Operational"
            active={isOperational}
            onClick={() => handleZoomLevelClick('OPERATIONAL')}
          />
        </ButtonGroup>

        <Divider />

        {/* Navigation */}
        <ButtonGroup>
          <Button icon="chevron-left" onClick={handlePrevPeriod} />
          <Button text="Today" onClick={handleToday} />
          <Button icon="chevron-right" onClick={handleNextPeriod} />
        </ButtonGroup>

        <Tag minimal style={{ fontFamily: 'monospace' }}>
          {format(new Date(canvasState.viewport.startDate), 'MMM yyyy')}
        </Tag>

        <Divider />

        {/* Zoom Controls */}
        <ButtonGroup>
          <Button icon="zoom-out" onClick={handleZoomOut} disabled={canvasState.zoom <= 0} />
          <Button icon="zoom-in" onClick={handleZoomIn} disabled={canvasState.zoom >= 20} />
        </ButtonGroup>

        <Tag minimal intent="primary">
          {canvasState.zoomLevel.replace('_', ' ')}
        </Tag>
      </div>

      <div style={{ display: 'flex', gap: '8px', alignItems: 'center' }}>
        {/* Scenario Indicator */}
        {scenarioState.activeScenarioId && (
          <Tag intent="warning" icon="annotation">
            Scenario Active
          </Tag>
        )}

        {/* Actions */}
        <Button
          icon="import"
          text="Import"
          onClick={handleImportData}
        />

        <Button
          icon="git-commit"
          text="Publish Baseline"
          onClick={handlePublishBaseline}
        />

        <Button
          icon="fork"
          text="Create Scenario"
          onClick={handleCreateScenario}
        />

        <Button
          intent="primary"
          icon="play"
          text="Run Optimizer"
          onClick={handleRunOptimizer}
          loading={uiState.loading.optimizer}
        />

        <Divider />

        {/* Overlays */}
        <Popover content={overlayMenu} placement="bottom-end">
          <Button icon="layers" text="Overlays" rightIcon="caret-down" />
        </Popover>

        {/* Export */}
        <Popover content={exportMenu} placement="bottom-end">
          <Button icon="export" text="Export" rightIcon="caret-down" />
        </Popover>

        {/* Help */}
        <Button
          minimal
          icon="help"
          onClick={() => uiActions.toggleHelpPanel()}
        />
      </div>
    </div>
  );
}
